const body = $input.first().json.body;

// Must be a callback_query (button press)
if (!body.callback_query) {
  console.log('Not a callback query — ignoring');
  return [];
}

const callbackData = body.callback_query.data;
const chatId       = body.callback_query.message.chat.id;
const messageId    = body.callback_query.message.message_id;
const firstName = body.callback_query.from.first_name || 'Brother/Sister';

console.log(`📲 Callback received: ${callbackData} from ${chatId}`);

// Format: yes_fajr_2 or no_fajr_2
const parts      = callbackData.split('_');
const answer     = parts[0]; // yes or no
const prayerKey  = parts[1]; // fajr, dhuhr etc
const contactId  = parts[2]; // contact id

const prayerNames = {
  fajr: 'Fajr', dhuhr: 'Dhuhr', asr: 'Asr', maghrib: 'Maghrib', isha: 'Isha'
};
const prayerEmojis = {
  fajr: '🌙', dhuhr: '☀️', asr: '🌤', maghrib: '🌇', isha: '🌃'
};

return [{
  json: {
    answer,
    prayerKey,
    prayerName:  prayerNames[prayerKey]  || prayerKey,
    prayerEmoji: prayerEmojis[prayerKey] || '🕌',
    contactId,
    chatId,
    messageId,
    firstName
  }
}];

