const groqResponse = $input.first().json;
const prevData = $('Parse Button Press').first().json;

let reminder;
try {
  const raw   = groqResponse.choices[0].message.content;
  const clean = raw.replace(/```json|```/g, '').trim();
  reminder    = JSON.parse(clean);
} catch(e) {
  // Offline fallback
  reminder = {
    arabic:     'فَوَيْلٌ لِّلْمُصَلِّينَ الَّذِينَ هُمْ عَن صَلَاتِهِمْ سَاهُونَ',
    source:     'Quran — Surah Al-Maun (107:4-5)',
    translation:'So woe to those who pray but are heedless of their prayer.',
    reflection: 'Allah is not only watching whether you pray — He watches whether you even care. Every missed salah is a call from Allah that we did not answer. The companions would tremble at the thought of missing even one prayer — may Allah make us from those who guard their salah.'
  };
}

const message = `😔 *${prevData.prayerEmoji} ${prevData.prayerName} — Missed Salah Reminder*\n\n` +
  `_${prevData.firstName}, Allah was calling you..._\n\n` +
  `*${reminder.arabic}*\n\n` +
  `📖 *${reminder.source}*\n` +
  `_"${reminder.translation}"_\n\n` +
  `${reminder.reflection}\n\n` +
  `🤲 _May Allah forgive us and make the next salah easy for us._`;

return [{
  json: {
    ...prevData,
    reminderMessage: message,
    reminder
  }
}];
